css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { min-height: 100vh; background: linear-gradient(160deg, #0ea5e9 0%, #0284c7 40%, #075985 100%); font-family: -apple-system, BlinkMacSystemFont, sans-serif; display: flex; align-items: center; justify-content: center; padding: 20px; }
.app { width: 100%; max-width: 400px; color: white; }
.search-bar { display: flex; gap: 10px; margin-bottom: 32px; }
.search-bar input { flex: 1; height: 48px; border-radius: 24px; border: none; background: rgba(255,255,255,0.2); color: white; padding: 0 20px; font-size: 15px; outline: none; backdrop-filter: blur(10px); } .search-bar input::placeholder { color: rgba(255,255,255,0.6); }
.search-bar button { width: 48px; height: 48px; border-radius: 50%; border: none; background: rgba(255,255,255,0.25); color: white; font-size: 18px; cursor: pointer; backdrop-filter: blur(10px); }
.weather-main { text-align: center; margin-bottom: 32px; }
.city-name { font-size: 28px; font-weight: 700; margin-bottom: 16px; opacity: 0.9; }
.weather-icon { font-size: 96px; margin-bottom: 8px; filter: drop-shadow(0 8px 16px rgba(0,0,0,0.2)); }
.temp { font-size: 80px; font-weight: 200; line-height: 1; margin-bottom: 8px; }
.feels { font-size: 14px; opacity: 0.7; margin-bottom: 8px; }
.condition { font-size: 22px; font-weight: 600; opacity: 0.9; }
.details { display: grid; grid-template-columns: repeat(4, 1fr); gap: 12px; margin-bottom: 28px; }
.detail-item { background: rgba(255,255,255,0.15); backdrop-filter: blur(10px); border-radius: 16px; padding: 16px 8px; text-align: center; }
.d-icon { font-size: 20px; margin-bottom: 8px; } .d-value { font-size: 14px; font-weight: 700; margin-bottom: 4px; } .d-label { font-size: 11px; opacity: 0.7; }
.forecast { background: rgba(255,255,255,0.15); backdrop-filter: blur(10px); border-radius: 20px; padding: 20px; }
.forecast-title { font-size: 14px; font-weight: 600; opacity: 0.7; margin-bottom: 16px; letter-spacing: 1px; }
.forecast-list { display: flex; flex-direction: column; gap: 12px; }
.forecast-item { display: flex; align-items: center; justify-content: space-between; }
.f-day { font-size: 14px; font-weight: 600; width: 80px; } .f-icon { font-size: 20px; } .f-bar-wrap { flex: 1; margin: 0 12px; height: 4px; background: rgba(255,255,255,0.2); border-radius: 2px; } .f-bar { height: 100%; border-radius: 2px; background: rgba(255,255,255,0.7); } .f-temps { font-size: 13px; font-weight: 600; text-align: right; min-width: 60px; } .f-temps small { opacity: 0.6; }

js:
const data = {
  'istanbul': { city: 'İstanbul', temp: 24, feels: 22, condition: 'Güneşli', icon: '☀️', humidity: '48%', wind: '12 km/s', visibility: '10 km', pressure: '1013 hPa', bg: 'linear-gradient(160deg,#0ea5e9,#0284c7,#075985)' },
  'ankara': { city: 'Ankara', temp: 18, feels: 15, condition: 'Parçalı Bulutlu', icon: '⛅', humidity: '55%', wind: '18 km/s', visibility: '8 km', pressure: '1008 hPa', bg: 'linear-gradient(160deg,#64748b,#475569,#334155)' },
  'izmir': { city: 'İzmir', temp: 28, feels: 30, condition: 'Çok Güneşli', icon: '🌤️', humidity: '40%', wind: '8 km/s', visibility: '15 km', pressure: '1016 hPa', bg: 'linear-gradient(160deg,#f59e0b,#d97706,#b45309)' },
  'antalya': { city: 'Antalya', temp: 32, feels: 35, condition: 'Sıcak', icon: '🔆', humidity: '38%', wind: '6 km/s', visibility: '20 km', pressure: '1018 hPa', bg: 'linear-gradient(160deg,#ef4444,#dc2626,#b91c1c)' },
  'trabzon': { city: 'Trabzon', temp: 16, feels: 14, condition: 'Yağmurlu', icon: '🌧️', humidity: '80%', wind: '22 km/s', visibility: '4 km', pressure: '1005 hPa', bg: 'linear-gradient(160deg,#1e3a5f,#1e40af,#1d4ed8)' }
};
const forecast = [
  { day: 'Pazartesi', icon: '☀️', min: 18, max: 26, pct: 90 },
  { day: 'Salı', icon: '⛅', min: 16, max: 23, pct: 70 },
  { day: 'Çarşamba', icon: '🌧️', min: 14, max: 19, pct: 40 },
  { day: 'Perşembe', icon: '🌤️', min: 17, max: 24, pct: 80 },
  { day: 'Cuma', icon: '☀️', min: 20, max: 28, pct: 95 }
];
function renderForecast() {
  document.getElementById('forecast').innerHTML = forecast.map(f => `
    <div class="forecast-item">
      <span class="f-day">${f.day}</span>
      <span class="f-icon">${f.icon}</span>
      <div class="f-bar-wrap"><div class="f-bar" style="width:${f.pct}%"></div></div>
      <span class="f-temps">${f.max}° <small>${f.min}°</small></span>
    </div>
  `).join('');
}
function loadCity(key) {
  const d = data[key] || data['istanbul'];
  document.getElementById('city').textContent = d.city;
  document.getElementById('temp').textContent = d.temp + '°';
  document.getElementById('feels').textContent = 'Hissedilen: ' + d.feels + '°';
  document.getElementById('condition').textContent = d.condition;
  document.getElementById('icon').textContent = d.icon;
  document.getElementById('humidity').textContent = d.humidity;
  document.getElementById('wind').textContent = d.wind;
  document.getElementById('visibility').textContent = d.visibility;
  document.getElementById('pressure').textContent = d.pressure;
  document.body.style.background = d.bg;
}
function search() {
  const val = document.getElementById('city-input').value.toLowerCase().trim();
  loadCity(val);
}
renderForecast();
loadCity('istanbul');
